import { useEffect, useState } from "react";

const SIZE = 10;

function point(x, y) {
  return { x, y };
}

function add(a, b) {
  return point(a.x + b.x, a.y + b.y);
}

function equal(a, b) {
  return a.x === b.x && a.y === b.y;
}

function randomFood() {
  return point(
    Math.floor(Math.random() * SIZE),
    Math.floor(Math.random() * SIZE)
  );
}

function progress(game) {
  const head = add(game.snake[0], game.direction);

  const snake = [
    head,
    ...game.snake,
  ];

  if (equal(head, game.food)) {
    return {
      ...game,
      snake,
      food: randomFood(),
    };
  }

  snake.pop();

  return {
    ...game,
    snake,
  };
}

export default function Snake() {
  const [game, setGame] = useState({
    snake: [point(5, 5)],
    food: point(2, 2),
    direction: point(0, 1),
  });

  useEffect(() => {
    const timer = setInterval(() => {
      setGame(progress);
    }, 300);

    return () => clearInterval(timer);
  }, []);

  function keyDown(e) {
    if (e.key === "ArrowUp")
      setGame(g => ({ ...g, direction: point(0, -1) }));

    if (e.key === "ArrowDown")
      setGame(g => ({ ...g, direction: point(0, 1) }));

    if (e.key === "ArrowLeft")
      setGame(g => ({ ...g, direction: point(-1, 0) }));

    if (e.key === "ArrowRight")
      setGame(g => ({ ...g, direction: point(1, 0) }));
  }

  function isSnake(cell) {
    return game.snake.some(
      part => equal(part, cell)
    );
  }

  function cellColor(cell) {
    if (isSnake(cell)) return "green";
    if (equal(game.food, cell)) return "red";
    return "white";
  }

  return (
    <main onKeyDown={keyDown} tabIndex={0}>
      <h1>🐍 Snake</h1>

      <table>
        <tbody>
          {Array.from({ length: SIZE }, (_, y) => (
            <tr key={y}>
              {Array.from({ length: SIZE }, (_, x) => (
                <td
                  key={x}
                  style={{
                    width: 25,
                    height: 25,
                    border: "1px solid",
                    background: cellColor(point(x, y)),
                  }}
                />
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
